import { QuestAulaValid } from './../model/QuestAulaValid';
import { UploadVideo } from './../model/UploadVideo';
import { Resposta } from './../model/RespostaAula';
import { QuestaoAula } from './../model/QuestaoAula';
import { environment } from './../../environments/environment.prod';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable, of } from 'rxjs';
import { delay } from 'rxjs/operators';

@Injectable({
  providedIn: 'root'
})
export class AtividadesRevisaoService {

  constructor(private http: HttpClient) { }

  token={ headers: new HttpHeaders().set('Authorization', environment.token) }

  private mockAulaTitulosByModulo: { [key: number]: string[] } = {
    1: ['Introdução ao Scrum', 'Papéis no Scrum', 'Eventos do Scrum', 'Backlog do Produto', 'Planejamento de Sprint', 'Estimativas Ágeis', 'Daily Scrum na prática', 'Review e Retrospectiva', 'Métricas e melhoria contínua', 'Projeto guiado com Scrum'],
    2: ['Algoritmos e lógica básica', 'Variáveis e tipos', 'Operadores e expressões', 'Estruturas condicionais', 'Laços de repetição', 'Vetores e matrizes', 'Funções e escopo', 'Depuração e testes básicos', 'Boas práticas de lógica', 'Desafio de lógica aplicado'],
    3: ['Fundamentos da linguagem Java', 'Estruturas de controle em Java', 'Métodos e parâmetros', 'Classes e objetos', 'Encapsulamento e herança', 'Polimorfismo e interfaces', 'Coleções Java', 'Tratamento de exceções', 'Entrada e saída de dados', 'Mini projeto em Java'],
    4: ['Modelagem de banco de dados', 'Comandos DDL', 'Comandos DML', 'Consultas com SELECT', 'Filtros e ordenação', 'Relacionamentos e JOINs', 'Funções de agregação', 'Subqueries e views', 'Índices e performance', 'Projeto SQL completo'],
    5: ['Introdução ao Spring Boot', 'Criando APIs REST', 'Entidades e JPA', 'Repositories e consultas', 'Camada de serviço', 'Validação de dados', 'Tratamento de exceções', 'Segurança básica', 'Testes com Spring', 'Projeto backend completo'],
    6: ['Introdução ao Android', 'Layout e componentes', 'Navegação entre telas', 'Consumo de API no app', 'Persistência local', 'Arquitetura MVVM', 'Gerenciamento de estado', 'Boas práticas de UX', 'Testes em Android', 'Projeto mobile completo'],
    7: ['HTML semântico', 'CSS e layout responsivo', 'JavaScript no navegador', 'Manipulação do DOM', 'Eventos e formulários', 'Consumo de APIs', 'Acessibilidade web', 'Versionamento com Git', 'Boas práticas frontend', 'Projeto web final'],
    8: ['Introdução ao Angular', 'Componentes e templates', 'Data binding e diretivas', 'Serviços e injeção de dependência', 'Roteamento Angular', 'Formulários reativos', 'HTTP e observables', 'Guards e interceptors', 'Testes em Angular', 'Projeto Angular completo'],
    9: ['Introdução ao React', 'JSX e componentes', 'Props e estado', 'Hooks essenciais', 'Renderização de listas', 'Formulários e eventos', 'Roteamento com React Router', 'Consumo de APIs no React', 'Testes de componentes', 'Projeto React completo']
  }

  private buildMockAulas(moduloId: number): UploadVideo[] {
    const titulos = this.mockAulaTitulosByModulo[moduloId] || Array.from({ length: 10 }, (_, index) => `Módulo ${moduloId} - Aula ${index + 1}`);
    return titulos.map((titulo, index) => ({
      id: (moduloId * 100) + (index + 1),
      titulo: titulo,
      descricao: `Conteúdo programático de ${titulo}`,
      linkVideo: 'https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4',
      linkGitHub: 'https://github.com/',
      linkDrive: 'https://drive.google.com/',
      num_sequencia: index + 1,
      modulo: null,
      questao: [],
      liberado: true
    } as UploadVideo));
  }

  private buildMockAtividades(userId: number, moduloId: number): QuestAulaValid[] {
    const aulas = this.buildMockAulas(moduloId);
    return aulas.map((aula) => ({
      aula: aula,
      usuario: { id: userId } as any,
      respondido: true,
      liberado: true
    } as QuestAulaValid));
  }

  postQuestao(questao: QuestaoAula){
    return this.http.post(`${environment.server}${environment.port}/checkuforuserquestion`, questao, this.token)
  }

  getByIdQuestao(id: number){
    return this.http.get(`${environment.server}${environment.port}/checkuforuserquestion/${id}`, this.token)
  }

  deleteQuestao(id: number){
    return this.http.delete(`${environment.server}${environment.port}/checkuforuserquestion/${id}`, this.token)
  }

  putQuestao(questao: QuestaoAula){
    return this.http.put(`${environment.server}${environment.port}/checkuforuserquestion`, questao, this.token)
  }


  getByIdResposta(id: number){
    return this.http.get(`${environment.server}${environment.port}/checkuforresp/${id}`, this.token)
  }

  postResposta(resposta: Resposta ){
    return this.http.post(`${environment.server}${environment.port}/checkuforresp`, resposta, this.token)
  }

  putResposta(resposta: Resposta){
    return this.http.put(`${environment.server}${environment.port}/checkuforresp`, resposta, this.token)
  }

  getByIdAula(id: number){
    return this.http.get(`${environment.server}${environment.port}/aula/${id}`, this.token)
  }

  getAulasByAtividade(userId: number, moduloId: number){
    if (environment.useMockServices) {
      return of(this.buildMockAtividades(userId, moduloId)).pipe(delay(150));
    }
    return this.http.get(`${environment.server}${environment.port}/check-for-understanding-valid/user-and-modulo/${userId}/${moduloId}`, this.token)
  }

  getAulasByAtividadByList(userId: number, moduloId: number){
    if (environment.useMockServices) {
      return of(this.buildMockAtividades(userId, moduloId)).pipe(delay(150));
    }
    return this.http.get(`${environment.server}${environment.port}/check-for-understanding-valid/user-and-modulo-by-list/${userId}/${moduloId}`, this.token)
  }

  postRespAtividade(quest: QuestAulaValid){
    if (environment.useMockServices) {
      return of(quest).pipe(delay(150));
    }
    return this.http.post(`${environment.server}${environment.port}/check-for-understanding-valid`, quest, this.token)
  }



}
