import { CronogramaCor } from './../model/CronogramaCor';
import { Cronograma } from './../model/Cronograma';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { environment } from './../../environments/environment';
import { Observable, of } from 'rxjs';
import { delay } from 'rxjs/operators';
@Injectable({
  providedIn: 'root'
})
export class CronogramaService {

  constructor(private http: HttpClient) { }

  token = {
    headers: new HttpHeaders().set
    ('Authorization', environment.token)
  };

  private mockCores: CronogramaCor[] = [
    { id: 1, rgb: '#3B82F6', nome: 'Azul' } as CronogramaCor,
    { id: 2, rgb: '#22C55E', nome: 'Verde' } as CronogramaCor,
    { id: 3, rgb: '#EF4444', nome: 'Vermelho' } as CronogramaCor
  ];

  private mockAgenda: Cronograma[] = this.buildRecurringAgenda();

  private formatDate(date: Date): string {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  }

  private buildRecurringAgenda(): Cronograma[] {
    const turmas = [
      { id: 1, descricao: 'Turma A' },
      { id: 2, descricao: 'Turma B' }
    ];
    const sessoes = [
      { descricao: 'Sessão técnica', inicio: '09:00', fim: '11:00', cor: this.mockCores[0] },
      { descricao: 'Prática guiada', inicio: '14:00', fim: '16:00', cor: this.mockCores[1] },
      { descricao: 'Mentoria e revisão', inicio: '16:15', fim: '17:30', cor: this.mockCores[2] }
    ];
    const agenda: Cronograma[] = [];
    const anoAtual = new Date().getFullYear();
    let idSequencial = 1;

    turmas.forEach((turma) => {
      for (let ano = anoAtual - 5; ano <= anoAtual + 5; ano++) {
        const cursor = new Date(ano, 0, 1);
        while (cursor.getFullYear() === ano) {
          const diaSemana = cursor.getDay();
          if (diaSemana >= 1 && diaSemana <= 5) {
            const data = this.formatDate(cursor);
            sessoes.forEach((sessao, index) => {
              agenda.push({
                id: idSequencial++,
                descricao: `${sessao.descricao} - ${turma.descricao}`,
                corRGB: sessao.cor,
                date: data,
                inicio: sessao.inicio,
                fim: sessao.fim,
                turma: { id: turma.id, descricao: turma.descricao } as any,
                link: `https://meet.example.com/turma-${turma.id}-${ano}-${index + 1}`
              } as Cronograma);
            });
          }
          cursor.setDate(cursor.getDate() + 1);
        }
      }
    });

    return agenda;
  }

  getByIdCor(id: number): Observable<any> {
    if (environment.useMockServices) {
      const cor = this.mockCores.find(item => item.id === Number(id)) || this.mockCores[0];
      return of(cor).pipe(delay(500));
    }
    return this.http.get(`${environment.server}${environment.port}/cor/${id}`, this.token);
  }

  getAllCor(): Observable<any> {
    if (environment.useMockServices) {
      return of(this.mockCores).pipe(delay(500));
    }
    return this.http.get(`${environment.server}${environment.port}/cor`, this.token);
  }

  postCor(cor: CronogramaCor): Observable<any> {
    if (environment.useMockServices) {
      return of({ ...cor, id: Date.now() }).pipe(delay(500));
    }
    return this.http.post(`${environment.server}${environment.port}/cor`, cor, this.token);
  }

  postAgenda(agenda: Cronograma): Observable<any> {
    if (environment.useMockServices) {
      const novoEvento = { ...agenda, id: this.mockAgenda.length + 1 } as Cronograma;
      this.mockAgenda.push(novoEvento);
      return of(novoEvento).pipe(delay(500));
    }
    return this.http.post(`${environment.server}${environment.port}/agenda`, agenda, this.token);
  }

  getAllAgenda(): Observable<any> {
    if (environment.useMockServices) {
      return of(this.mockAgenda).pipe(delay(500));
    }
    return this.http.get(`${environment.server}${environment.port}/agenda`, this.token);
  }

  putAgenda(agenda: Cronograma): Observable<any> {
    if (environment.useMockServices) {
      const index = this.mockAgenda.findIndex(item => item.id === Number(agenda.id));
      if (index > -1) {
        this.mockAgenda[index] = agenda;
      }
      return of(agenda).pipe(delay(500));
    }
    return this.http.put(`${environment.server}${environment.port}/agenda`, agenda, this.token);
  }

  getByIdAgenda(id: number): Observable<any> {
    if (environment.useMockServices) {
      const evento = this.mockAgenda.find(item => item.id === Number(id));
      return of(evento).pipe(delay(500));
    }
    return this.http.get(`${environment.server}${environment.port}/agenda/${id}`, this.token);
  }

  deleteAgenda(id: number): Observable<any> {
    if (environment.useMockServices) {
      this.mockAgenda = this.mockAgenda.filter(item => item.id !== Number(id));
      return of({ deleted: true, id }).pipe(delay(500));
    }
    return this.http.delete(`${environment.server}${environment.port}/agenda/${id}`, this.token);
  }

  getByIdTurma(idTurma: number): Observable<any> {
    if (environment.useMockServices) {
      const eventosTurma = this.mockAgenda.filter(item => item.turma.id === Number(idTurma));
      return of(eventosTurma).pipe(delay(500));
    }
    return this.http.get(`${environment.server}${environment.port}/agenda/turma/${idTurma}`, this.token);
  }

}
